const formatCurrency = (value: number | null | undefined) => {
  const val = value || 0;
  return new Intl.NumberFormat('pt-AO', { style: 'currency', currency: 'AOA' }).format(val).replace('AOA', 'Kz');
};

const formatDate = (date: any) => {
  if (!date) return '---';
  const d = new Date(date);
  if (isNaN(d.getTime())) return '---';
  return d.toLocaleDateString('pt-AO');
};

const writeValorPorExtenso = (n: number) => {
  if (n === 0) return 'Zero Kwanzas';
  
  const unidades = ['', 'um', 'dois', 'três', 'quatro', 'cinco', 'seis', 'sete', 'oito', 'nove'];
  const dezena_10 = ['dez', 'onze', 'doze', 'treze', 'catorze', 'quinze', 'dezasseis', 'dezassete', 'dezoito', 'dezanove'];
  const dezenas = ['', '', 'vinte', 'trinta', 'quarenta', 'cinquenta', 'sessenta', 'setenta', 'oitenta', 'noventa'];
  const centenas = ['', 'cem', 'duzentos', 'trezentos', 'quatrocentos', 'quinhentos', 'seiscentos', 'setecentos', 'oitocentos', 'novecentos'];

  const convertGroup = (n: number) => {
    let res = '';
    if (n === 100) return 'cem';
    if (n >= 100) {
      const c = Math.floor(n / 100);
      res += (c === 1 && n % 100 !== 0 ? 'cento' : centenas[c]);
      n %= 100;
      if (n > 0) res += ' e ';
    }
    if (n >= 20) {
      res += dezenas[Math.floor(n / 10)];
      n %= 10;
      if (n > 0) res += ' e ';
    } else if (n >= 10) {
      res += dezena_10[n - 10];
      n = 0;
    }
    if (n > 0) res += unidades[n];
    return res;
  };

  const integerPart = Math.floor(n);
  const centsPart = Math.round((n - integerPart) * 100);
  
  let result = '';
  
  const scales = [
    { label: [' quintilhão', ' quintilhões'], value: 1e18 },
    { label: [' quatrilhão', ' quatrilhões'], value: 1e15 },
    { label: [' trilião', ' triliões'], value: 1e12 },
    { label: [' bilião', ' biliões'], value: 1e9 },
    { label: [' milhão', ' milhões'], value: 1e6 },
    { label: [' mil', ' mil'], value: 1e3 }
  ];

  let remaining = integerPart;

  for (const scale of scales) {
    if (remaining >= scale.value) {
      const count = Math.floor(remaining / scale.value);
      if (scale.value === 1000 && count === 1) {
        result += 'mil';
      } else {
        result += convertGroup(count) + (count === 1 ? scale.label[0] : scale.label[1]);
      }
      remaining %= scale.value;
      if (remaining > 0) result += (remaining < 100 || remaining % 100 === 0 ? ' e ' : ', ');
    }
  }
  
  if (remaining > 0 || result === '') {
    result += convertGroup(remaining);
  }

  result += (integerPart === 1 ? ' Kwanza' : ' Kwanzas');
  
  if (centsPart > 0) {
    result += ' e ' + convertGroup(centsPart) + (centsPart === 1 ? ' cêntimo' : ' cêntimos');
  }
  
  return result.charAt(0).toUpperCase() + result.slice(1);
};

const calculateIRT = (salary: number | null | undefined) => {
  const s = salary || 0;
  if (s <= 100000) return 0;
  if (s <= 150000) return (s - 100000) * 0.10;
  if (s <= 200000) return 5000 + (s - 150000) * 0.13;
  if (s <= 300000) return 11500 + (s - 200000) * 0.16;
  if (s <= 500000) return 27500 + (s - 300000) * 0.18;
  if (s <= 1000000) return 63500 + (s - 500000) * 0.19;
  if (s <= 1500000) return 158500 + (s - 1000000) * 0.20;
  if (s <= 2000000) return 258500 + (s - 1500000) * 0.21;
  if (s <= 5000000) return 363500 + (s - 2000000) * 0.22;
  if (s <= 10000000) return 1023500 + (s - 5000000) * 0.23;
  return 2173500 + (s - 10000000) * 0.25;
};

