const WorkplaceModule = ({ 
  workplaces, 
  onRefresh, 
  onAddWorkSite, 
  onUpdateWorkSite, 
  onDeleteWorkSite,
  clients, 
  issuedDocuments, 
  workSiteMovements,
  employees = [],
  allWorkSites = []
}: { 
  workplaces: WorkSite[], 
  onRefresh: () => void, 
  onAddWorkSite: (site: Omit<WorkSite, 'id'>) => void,
  onUpdateWorkSite: (id: any, site: Omit<WorkSite, 'id'>) => void,
  onDeleteWorkSite: (id: any) => void,
  clients: Client[], 
  issuedDocuments: IssuedDocument[], 
  workSiteMovements: WorkSiteMovement[],
  employees?: Employee[],
  allWorkSites?: WorkSite[]
}) => {
  const { user } = useAuth();
  const [selectedWorkplace, setSelectedWorkplace] = useState<WorkSite | null>(null);
  const [showForm, setShowForm] = useState(false);
  const [editingWorkplace, setEditingWorkplace] = useState<WorkSite | null>(null);
  
  const [clientId, setClientId] = useState('');
  const [name, setName] = useState('');
  const [location, setLocation] = useState('');
  const [code, setCode] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [staffPerDay, setStaffPerDay] = useState(0);
  const [totalStaff, setTotalStaff] = useState(0);
  const [description, setDescription] = useState('');
  const [contact, setContact] = useState('');
  const [observations, setObservations] = useState('');

  // Sync edit mode fields
  useEffect(() => {
    if (editingWorkplace) {
      setClientId(String(editingWorkplace.client_id || ''));
      setName(editingWorkplace.title || editingWorkplace.name || '');
      setLocation(editingWorkplace.location || '');
      setCode(editingWorkplace.code || '');
      setStartDate(editingWorkplace.start_date ? editingWorkplace.start_date.substring(0, 10) : '');
      setEndDate(editingWorkplace.end_date ? editingWorkplace.end_date.substring(0, 10) : '');
      setStaffPerDay(Number(editingWorkplace.staff_per_day || 0));
      setTotalStaff(Number(editingWorkplace.total_staff || 0));
      setDescription(editingWorkplace.description || '');
      setContact(editingWorkplace.contact || '');
      setObservations(editingWorkplace.observations || '');
    } else {
      setClientId('');
      setName('');
      setLocation('');
      setCode('');
      setStartDate('');
      setEndDate('');
      setStaffPerDay(0);
      setTotalStaff(0);
      setDescription('');
      setContact('');
      setObservations('');
    }
  }, [editingWorkplace]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    
    const client = clients?.find(c => String(c.id) === String(clientId));
    
    const payload = {
      client_id: clientId,
      client_name: client?.name || '',
      title: name,
      location,
      contact,
      description,
      observations,
      code,
      start_date: startDate,
      end_date: endDate,
      staff_per_day: staffPerDay,
      total_staff: totalStaff
    };

    if (editingWorkplace && editingWorkplace.id) {
      onUpdateWorkSite(editingWorkplace.id, payload);
    } else {
      onAddWorkSite(payload);
    }
    
    setShowForm(false);
    setEditingWorkplace(null);
  };

  const handleEditClick = (w: WorkSite) => {
    setEditingWorkplace(w);
    setShowForm(true);
  };

  if (selectedWorkplace) {
    return (
      <WorkSiteManagement 
        workSite={selectedWorkplace} 
        movements={workSiteMovements} 
        invoices={issuedDocuments} 
        onBack={() => setSelectedWorkplace(null)}
        employees={employees}
        allWorkSites={workplaces}
        onRefreshEmployees={onRefresh}
      />
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div className="space-y-1">
          <h2 className="text-2xl font-bold text-zinc-800 flex items-center gap-3">
            <MapPin size={24} className="text-[#003366]" />
            Locais de Trabalho
          </h2>
          <p className="text-zinc-500 text-sm">Gestão de obras e locais de prestação de serviços da empresa.</p>
        </div>
        <button 
          onClick={() => { setEditingWorkplace(null); setShowForm(true); }}
          className="bg-[#003366] text-white px-6 py-2.5 font-bold text-xs uppercase tracking-widest flex items-center gap-2"
        >
          <Plus size={18} /> Novo Local
        </button>
      </div>

      <div className="bg-white border border-zinc-200 shadow-none overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-[#003366] text-white text-[11px] uppercase tracking-wider font-bold">
              <th className="px-6 py-4">Código</th>
              <th className="px-6 py-4">Nome / Designação</th>
              <th className="px-6 py-4">Localização</th>
              <th className="px-6 py-4">Cliente Associado</th>
              <th className="px-6 py-4 text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-zinc-100">
            {workplaces.length === 0 ? (
               <tr><td colSpan={5} className="p-12 text-center text-zinc-400 italic">Nenhum local de trabalho registado.</td></tr>
            ) : workplaces.map((w) => (
              <tr key={w.id} className="hover:bg-zinc-50 transition-colors text-sm">
                <td className="px-6 py-4 font-mono text-xs font-bold text-[#003366]">{w.code || 'N/A'}</td>
                <td className="px-6 py-4 font-bold text-zinc-900">{w.title || w.name}</td>
                <td className="px-6 py-4 text-zinc-600">{w.location || 'N/A'}</td>
                <td className="px-6 py-4 text-zinc-500 font-bold">{w.client_name || 'N/A'}</td>
                <td className="px-6 py-4 text-right">
                  <button 
                    onClick={() => setSelectedWorkplace(w)}
                    className="bg-zinc-50 text-[#003366] px-3 py-1 text-[10px] font-black uppercase tracking-widest border border-zinc-200 hover:bg-zinc-100 transition-all mr-2"
                  >
                    Ver Relatório
                  </button>
                  <button 
                    onClick={() => handleEditClick(w)}
                    className="bg-amber-50 text-amber-700 px-3 py-1 text-[10px] font-black uppercase tracking-widest border border-amber-100 hover:bg-amber-100 transition-all mr-2"
                  >
                    Editar
                  </button>
                  <button 
                    onClick={() => onDeleteWorkSite(w.id)}
                    className="bg-red-50 text-red-600 px-3 py-1 text-[10px] font-black uppercase tracking-widest border border-red-100 hover:bg-red-100 transition-all mr-2"
                  >
                    Eliminar
                  </button>
                  <button className="text-zinc-400 hover:text-[#003366]"><MoreHorizontal size={18} /></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showForm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-zinc-900/60 backdrop-blur-sm">
          <motion.div 
            initial={{ opacity: 0, scale: 0.95 }}
            animate={{ opacity: 1, scale: 1 }}
            className="w-full max-w-4xl max-h-[90vh] overflow-y-auto bg-white p-8 rounded-none shadow-2xl"
          >
            <div className="flex justify-between items-center mb-6 border-b border-zinc-100 pb-4">
              <h3 className="font-bold text-[#003366] text-xl uppercase tracking-tight text-center w-full">
                {editingWorkplace ? 'Atualizar Local de Trabalho' : 'Novo Local de Trabalho'}
              </h3>
              <button type="button" onClick={() => { setShowForm(false); setEditingWorkplace(null); }} className="text-zinc-400 hover:text-zinc-600 absolute right-8">
                <X size={24} />
              </button>
            </div>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">Seleccione um Cliente</label>
                  <select 
                    value={clientId} onChange={e => setClientId(e.target.value)} required
                    className="w-full border border-zinc-200 bg-white rounded-none px-4 py-2.5 text-sm focus:outline-none focus:border-[#003366]"
                  >
                    <option value="">Selecionar Cliente...</option>
                    {clients?.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                  </select>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">Código</label>
                  <input type="text" value={code} onChange={e => setCode(e.target.value)} className="w-full border border-zinc-200 bg-white rounded-none px-4 py-2.5 text-sm focus:outline-none focus:border-[#003366]" placeholder="Ex: OBRA-001" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">Titulo da Obra/Serviço (Nome)</label>
                  <input type="text" required value={name} onChange={e => setName(e.target.value)} className="w-full border border-zinc-200 bg-white rounded-none px-4 py-2.5 text-sm focus:outline-none focus:border-[#003366]" placeholder="Ex: Edifício Kilamba" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">Localização</label>
                  <input type="text" value={location} onChange={e => setLocation(e.target.value)} className="w-full border border-zinc-200 bg-white rounded-none px-4 py-2.5 text-sm focus:outline-none focus:border-[#003366]" placeholder="Ex: Luanda, Talatona" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">Data de Abertura de Obra/Serviço</label>
                  <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} required className="w-full border border-zinc-200 bg-white rounded-none px-4 py-2.5 text-sm focus:outline-none focus:border-[#003366]" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">Data de Encerramento de Obra/Serviço</label>
                  <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} required className="w-full border border-zinc-200 bg-white rounded-none px-4 py-2.5 text-sm focus:outline-none focus:border-[#003366]" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">Total de Pessoal</label>
                  <input type="number" value={totalStaff} onChange={e => setTotalStaff(Number(e.target.value))} className="w-full border border-zinc-200 bg-white rounded-none px-4 py-2.5 text-sm focus:outline-none focus:border-[#003366]" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">Pessoal por Dia</label>
                  <input type="number" value={staffPerDay} onChange={e => setStaffPerDay(Number(e.target.value))} className="w-full border border-zinc-200 bg-white rounded-none px-4 py-2.5 text-sm focus:outline-none focus:border-[#003366]" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">Contacto</label>
                  <input type="text" value={contact} onChange={e => setContact(e.target.value)} className="w-full border border-zinc-200 bg-white rounded-none px-4 py-2.5 text-sm focus:outline-none focus:border-[#003366]" />
                </div>
                <div className="col-span-1 md:col-span-2 space-y-1.5">
                  <label className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">Descrição</label>
                  <input type="text" value={description} onChange={e => setDescription(e.target.value)} className="w-full border border-zinc-200 bg-white rounded-none px-4 py-2.5 text-sm focus:outline-none focus:border-[#003366]" />
                </div>
                <div className="col-span-1 md:col-span-2 space-y-1.5">
                  <label className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">Observações</label>
                  <textarea value={observations} onChange={e => setObservations(e.target.value)} className="w-full border border-zinc-200 bg-white rounded-none px-4 py-2.5 text-sm focus:outline-none focus:border-[#003366] min-h-[80px]" />
                </div>
              </div>
              <div className="flex justify-end gap-4 mt-6 border-t border-zinc-100 pt-6">
                <button type="button" onClick={() => { setShowForm(false); setEditingWorkplace(null); }} className="px-6 py-2.5 font-bold text-sm tracking-widest bg-zinc-100 text-zinc-500 hover:bg-zinc-200 uppercase">Cancelar</button>
                <button type="submit" className="bg-[#003366] text-white font-bold py-2.5 px-8 uppercase text-xs tracking-widest hover:bg-[#002244]">
                  {editingWorkplace ? 'Salvar Alterações' : 'Registar Local'}
                </button>
              </div>
            </form>
          </motion.div>
        </div>
      )}
    </div>
  );
};

const PERMISSION_EQUIVALENTS: Record<string, string[]> = {
  dashboard: ['dashboard', 'painel', 'painel_de_bordo', 'painel de bordo'],
  clients: ['clients', 'clientes'],
  workplaces: ['workplaces', 'locais_trabalho', 'locais de trabalho'],
  secretary: ['secretary', 'secretaria', 'secretaria beta', 'secretaria_beta'],
  pos: ['pos', 'ponto_venda', 'ponto de venda'],
  contracts: ['contracts', 'contratos'],
  electronic_invoices: ['electronic_invoices', 'faturacao_electronica', 'faturação electrónica', 'faturação eletrónica', 'faturacao electronica'],
  security: ['security', 'seguranca', 'segurança', 'segurança gestão privada', 'segurança gestão', 'seguranca gestao privada'],
  specialized: ['specialized', 'gestao_especializada', 'gestão especializada'],
  archive: ['archive', 'arquivo'],
  invoices: ['invoices', 'vendas'],
  drafts: ['drafts', 'rascunhos', 'rascunhos (drafts)'],
  suppliers: ['suppliers', 'compras'],
  products: ['products', 'produtos', 'stocks', 'inventário', 'stocks & inventário'],
  financial: ['financial', 'financas', 'finanças'],
  accounting: ['accounting', 'contabilidade'],
  hr: ['hr', 'rh', 'recursos_humanos', 'recursos humanos'],
  reports: ['reports', 'relatorios', 'relatórios'],
  agrobusiness: ['agrobusiness', 'agronegocio', 'agronegócio'],
  church: ['church', 'igreja', 'gestao_de_igreja', 'gestão de igreja'],
  settings: ['settings', 'definicoes', 'definições']
};

const mapPermissionAreasFromDB = (dbAreas: string[]): string[] => {
  const result = new Set<string>();
  const areas = (dbAreas || []).map(a => String(a).trim().toLowerCase());
  
  Object.keys(PERMISSION_EQUIVALENTS).forEach(moduleId => {
    const possibleKeys = (PERMISSION_EQUIVALENTS[moduleId] || []).map(k => k.trim().toLowerCase());
    if (possibleKeys.some(key => areas.includes(key))) {
      result.add(moduleId);
    }
  });

  return Array.from(result);
};

const mapPermissionAreasForDB = (selectedIds: string[]): string[] => {
  const result = new Set<string>();
  
  (selectedIds || []).forEach(id => {
    result.add(id);
    const equivalentsList = PERMISSION_EQUIVALENTS[id];
    if (equivalentsList) {
      equivalentsList.forEach(eq => result.add(eq.trim().toLowerCase()));
    }
  });
  
  return Array.from(result).map(a => a.toLowerCase());
};

const hasModulePermission = (user: any, moduleId: string): boolean => {
  const isGlobalAdmin = user?.is_admin === true || 
                        user?.role === 'admin' || 
                        user?.role === 'admin_empresa' || 
                        user?.role === 'super_admin' || 
                        user?.role === 'proprietario' || 
                        (user?.level !== undefined && Number(user.level) >= 10);
  
  if (isGlobalAdmin) return true;
  if (moduleId === 'dashboard') return true;
  
  const rawPermissions = user?.permission_areas;
  const permissions = Array.isArray(rawPermissions) 
    ? rawPermissions.map(p => String(p).trim().toLowerCase()) 
    : [];
    
  if (permissions.length === 0) return false;
  
  const possibleKeys = (PERMISSION_EQUIVALENTS[moduleId] || [moduleId]).map(k => k.trim().toLowerCase());
  return possibleKeys.some(key => permissions.includes(key));
};

