  const handleDismissEmployeeWrapper = async () => {
    if (!selectedEmployeeForOptions) return;
    try {
      // Sincronizar com o Supabase na tabela colaboradores
      if (user?.empresa_id) {
        try {
          await supabase
            .from('colaboradores')
            .update({
              status: 'dismissed',
              dismissed_at: dismissData.date,
              dismissal_reason: dismissData.reason,
              dismissal_ordered_by: dismissData.orderedBy,
              dismissal_observations: dismissData.observations
            })
            .eq('id', selectedEmployeeForOptions.id)
            .eq('empresa_id', user.empresa_id);
        } catch (supaErr) {
          console.error('[DismissEmployee] Erro ao sincronizar com Supabase:', supaErr);
        }
      }

      const res = await fetchWithAuth(`/api/employees/dismiss/${selectedEmployeeForOptions.id}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(dismissData)
      });
      if (res.ok) {
        alert('Funcionário demitido com sucesso!');
        setShowDismissForm(false);
        setShowOptionsMenu(false);
        fetchHRData();
      }
    } catch (err) {
      console.error('Error dismissing employee:', err);
    }
  };

  const handleReadmitEmployee = async (employeeId: number, date: string, reason?: string, orderedBy?: string, observations?: string) => {
    try {
      // Immediate local state update for responsiveness
      setLocalEmployees(prev => prev.map(emp => {
        if (emp.id === employeeId) {
          return { ...emp, status: 'active', dismissed_at: undefined, is_blocked: false };
        }
        return emp;
      }));

      if (user?.empresa_id) {
        try {
          await supabase
            .from('colaboradores')
            .update({
              status: 'active',
              dismissed_at: null,
              dismissal_reason: null,
              dismissal_ordered_by: null,
              dismissal_observations: null
            })
            .eq('id', employeeId)
            .eq('empresa_id', user.empresa_id);
        } catch (supaErr) {
          console.error('[ReadmitEmployee] Erro ao sincronizar com Supabase:', supaErr);
        }
      }

      const res = await fetchWithAuth(`/api/employees/readmit/${employeeId}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ date, reason, orderedBy, observations })
      });
      if (res.ok) {
        alert('Funcionário readmitido com sucesso! O mesmo já está desbloqueado no sistema.');
        fetchHRData();
      }
    } catch (err) {
      console.error('Error readmitting employee:', err);
      alert('Ocorreu um erro ao tentar readmitir o funcionário.');
    }
  };

