    setRua(emp.rua || '');
    setZona(emp.zona || '');
    setBairro(emp.bairro || '');
    setProvinciaMorada(emp.provincia_morada || '');
    setMunicipioMorada(emp.municipio_morada || '');
    setCodigoPostal(emp.codigo_postal || '0000-00');
