                            <td className="px-6 py-4">
                              <input 
                                type="checkbox"
                                checked={selectedReceiptIds.includes(receipt.id)}
                                onChange={(e) => {
                                  if (e.target.checked) {
                                    setSelectedReceiptIds(prev => [...prev, receipt.id]);
                                  } else {
                                    setSelectedReceiptIds(prev => prev.filter(id => id !== receipt.id));
                                  }
                                }}
                                className="accent-[#003366]"
                              />
                            </td>
